module RefModule(
  input clk,
  input rst,
  output [m-1:0] out
);parameter n = 4; // number of states
parameter m = 2; // number of output signals

reg [n-1:0] unused_state;
reg [m-1:0] out_reg;

// Define the output signals as functions of the current unused_state
always @ (unused_state) begin
  case (unused_state)
    0: out_reg = {1'b0, 1'b0};
    1: out_reg = {1'b0, 1'b1};
    2: out_reg = {1'b1, 1'b0};
    3: out_reg = {1'b1, 1'b1};
  endcase
end

// Define the unused_state transitions
always @ (posedge clk, posedge rst) begin
  if (rst) begin
    unused_state <= 0;
  end else begin
    case (unused_state)
      0: unused_state <= 1;
      1: unused_state <= 2;
      2: unused_state <= 3;
      3: unused_state <= 0;
    endcase
  end
end

// Assign the output signals
assign out = out_reg;

endmodule
